// Runs once over ALL unread emails.
// Tags each email with its chunk number and the total chunk count,
// and flattens the Outlook message into clean fields for the AI.
const items = $input.all();
const total = items.length;
const totalBatches = Math.ceil(total / 10);

return items.map((item, i) => {
  const m = item.json;
  const from = m.from?.emailAddress?.address
    || m.sender?.emailAddress?.address
    || 'Unknown sender';
  const fromName = m.from?.emailAddress?.name
    || m.sender?.emailAddress?.name
    || '';
  // Prefer the short preview; fall back to stripping HTML from the body.
  let bodyPreview = m.bodyPreview || '';
  if (!bodyPreview && m.body?.content) {
    bodyPreview = String(m.body.content).replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  }
  bodyPreview = bodyPreview.slice(0, 600);

  return {
    json: {
      from,
      fromName,
      subject: m.subject || '(no subject)',
      bodyPreview,
      receivedDateTime: m.receivedDateTime || '',
      batchNumber: Math.floor(i / 10) + 1,
      totalBatches,
    },
  };
});

// Runs once per loop pass over the CURRENT batch (up to 10 emails).
// Collapses the batch into a single item containing one text block
// for the AI, plus the carried-through batch metadata.
const items = $input.all();
const batchNumber = items[0].json.batchNumber;
const totalBatches = items[0].json.totalBatches;
const count = items.length;

const emailsText = items.map((it, idx) => {
  const e = it.json;
  const sender = e.fromName ? `${e.fromName} <${e.from}>` : e.from;
  return [
    `Email ${idx + 1}:`,
    `From: ${sender}`,
    `Received: ${e.receivedDateTime}`,
    `Subject: ${e.subject}`,
    `Body: ${e.bodyPreview}`,
  ].join('\n');
}).join('\n\n---\n\n');

return [{
  json: {
    batchNumber,
    totalBatches,
    count,
    emailsText,
  },
}];
